// StatReport_상태확인 노드에서 downloadUrl 가져오기
const downloadUrl = $('StatReport_상태확인').item.json.downloadUrl;

// HMAC-SHA256 서명 생성 (GET /report-download)
// 주의: 서명에 쓰는 uri는 path만 (쿼리스트링 제외)
const timestamp = Date.now().toString();
const method = 'GET';
const uri = '/report-download';

const message = `${timestamp}.${method}.${uri}`;
const signature = crypto
  .createHmac('sha256', secretKey)
  .update(message)
  .digest('base64');

return [{
  json: {
    timestamp: timestamp,
    signature: signature,
    api_key: apiKey,
    customer_id: customerId,
    downloadUrl: downloadUrl,  // 쿼리스트링 포함 full URL (HTTP Request에서 사용)
  }
}];

const raw = $input.first().json.data;
if (!raw || typeof raw !== 'string') {
  throw new Error('TSV data not found');
}

const lines = raw.split('\n').filter(l => l.trim().length > 0);
const byProduct = {};

for (const line of lines) {
  const cols = line.split('\t');
  if (cols.length < 14) continue;

  const date = cols[0];
  const campaignId = cols[2];
  const adgroupId = cols[3];
  const adId = cols[5];
  const nvMid = cols[7];
  const impCnt = parseInt(cols[9]) || 0;
  const clkCnt = parseInt(cols[10]) || 0;
  const salesAmt = parseFloat(cols[11]) || 0;   // 광고비 (VAT포함)
  const rankSum = parseFloat(cols[12]) || 0;    // ← 수정: 이미 "순위×노출" 가중합
  const ccnt = parseInt(cols[13]) || 0;

  if (impCnt === 0) continue;

  if (!byProduct[adId]) {
    byProduct[adId] = {
      date, campaignId, adgroupId, adId, nvMid,
      impCnt: 0, clkCnt: 0, salesAmt: 0, ccnt: 0,
      rankWeightedSum: 0, rankWeightTotal: 0
    };
  }

  const p = byProduct[adId];
  p.impCnt += impCnt;
  p.clkCnt += clkCnt;
  p.salesAmt += salesAmt;
  p.ccnt += ccnt;
  p.rankWeightedSum += rankSum;    // ← 수정: 재곱 제거, 그대로 누적
  p.rankWeightTotal += impCnt;
}

const formatDate = (d) => d.substring(0,4) + '-' + d.substring(4,6) + '-' + d.substring(6,8);

const results = Object.values(byProduct).map((p) => {
  const ctr = p.impCnt > 0 ? (p.clkCnt / p.impCnt) * 100 : 0;
  const crto = p.clkCnt > 0 ? (p.ccnt / p.clkCnt) * 100 : 0;
  const avgRnk = p.rankWeightTotal > 0 ? (p.rankWeightedSum / p.rankWeightTotal) : 0;

  return {
    json: {
      수집일: formatDate(p.date),
      채널: '쇼핑검색광고',
      캠페인ID: p.campaignId,
      광고그룹ID: p.adgroupId,
      상품ID: p.adId,
      nvMid: p.nvMid,
      노출: p.impCnt,
      클릭: p.clkCnt,
      CTR: Number(ctr.toFixed(2)),
      비용: p.salesAmt,
      전환수: p.ccnt,
      전환율: Number(crto.toFixed(2)),
      매출: 0,
      ROAS: 0,
      평균노출순위: Number(avgRnk.toFixed(1))
    }
  };
});

return results;

